action.old_str:
if (auto funcType = texp->dcst<FunctionType>()) {
    auto fdecl = make<FunctionDecl>();
    auto type = make<Type>();
    fdecl->type = type;

    type->spec = sq.first;
    type->qual = sq.second;
    type->texp = funcType;

    fdecl->name = std::move(name);
    for (auto p : funcType->params) {
      auto paramDecl = make<VarDecl>();
      paramDecl->type = p;
      fdecl->params.push_back(paramDecl);
    }

action.new_str:
if (auto funcType = texp->dcst<FunctionType>()) {
    auto fdecl = make<FunctionDecl>();
    auto type = make<Type>();
    fdecl->type = type;

    type->spec = sq.first;
    type->qual = sq.second;
    type->texp = funcType;

    fdecl->name = std::move(name);
    for (size_t i = 0; i < funcType->params.size(); i++) {
      auto paramDecl = make<VarDecl>();
      paramDecl->type = funcType->params[i];
      paramDecl->name = i < funcType->paramNames.size() ? funcType->paramNames[i] : "";
      fdecl->params.push_back(paramDecl);
    }

